 1	import * as React from "react";
 2	
 3	import { NodeCondition, NodeKind } from "../types/node";
 4	import Status from "../status/Status";
 5	import { Condition } from "../console-app/queries";
 6	import NodeUnschedulableStatus from "./NodeUnschedulableStatus";
 7	import SecondaryStatus from "../status/SecondaryStatus";
 8	import { Button } from "@patternfly/react-core";
 9	import { startCase, get, find } from "lodash-es";
10	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
11	
12	const isNodeUnschedulable = (node: NodeKind): boolean =>
13	  get(node, "spec.unschedulable", false);
14	
15	const isNodeReady = (node: NodeKind): boolean => {
16	  const conditions = get(node, "status.conditions", []);
17	  const readyState = find(conditions, { type: "Ready" }) as NodeCondition;
18	
19	  return readyState && readyState.status === "True";
20	};
21	
22	export const nodeStatus = (node: NodeKind) =>
23	  isNodeReady(node) ? "Ready" : "Not Ready";
24	
25	const getNodeSecondaryStatus = (node: NodeKind): string[] => {
26	  const { t } = useNodeHealthCheckTranslation();
27	  const states = [];
28	  if (isNodeUnschedulable(node)) {
29	    states.push(t("Scheduling disabled"));
30	  }
31	  return states;
32	};
33	
34	const isMonitoredCondition = (condition: Condition): boolean =>
35	  [
36	    Condition.DISK_PRESSURE,
37	    Condition.MEM_PRESSURE,
38	    Condition.PID_PRESSURE,
39	  ].includes(condition);
40	
41	const getDegradedStates = (node: NodeKind): Condition[] => {
42	  return node.status.conditions
43	    .filter(
44	      ({ status, type }) =>
45	        status === "True" && isMonitoredCondition(type as Condition)
46	    )
47	    .map(({ type }) => type as Condition);
48	};
49	
50	const NodeStatus: React.FC<NodeStatusProps> = ({
51	  node,
52	  showPopovers = false,
53	  className,
54	}) => {
55	  const status = showPopovers ? getDegradedStates(node) : [];
56	  return (
57	    <>
58	      {!node.spec.unschedulable ? (
59	        <Status status={nodeStatus(node)} className={className} />
60	      ) : (
61	        <NodeUnschedulableStatus
62	          status={nodeStatus(node)}
63	          className={className}
64	        />
65	      )}
66	      <SecondaryStatus status={getNodeSecondaryStatus(node)} />
67	      {status.length > 0 &&
68	        status.map((item) => (
69	          <div key={item}>
70	            <Button variant="link" isInline>
71	              {startCase(item)}
72	            </Button>
73	          </div>
74	        ))}
75	    </>
76	  );
77	};
78	
79	type NodeStatusProps = {
80	  node: NodeKind;
81	  showPopovers?: boolean;
82	  className?: string;
83	};
84	
85	export default NodeStatus;

